namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = "Baguette\nTomatoes\nFresh basil\nGarlic\nOlive oil\nBalsamic vinegar",
            Steps = "1. Slice and toast baguette\n2. Dice tomatoes and mix with basil, garlic, oil\n3. Spoon onto bread and drizzle with balsamic",
            AverageRating = 4.2, RatingCount = 5
        },
        new Recipe
        {
            Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = "Button mushrooms\nCream cheese\nGarlic\nParsley\nBreadcrumbs\nParmesan",
            Steps = "1. Remove mushroom stems and hollow caps\n2. Mix cream cheese, garlic, parsley, breadcrumbs\n3. Fill caps and top with parmesan\n4. Bake at 375°F for 20 minutes",
            AverageRating = 4.5, RatingCount = 8
        },
        new Recipe
        {
            Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = "Spaghetti\nPancetta\nEggs\nParmesan\nBlack pepper",
            Steps = "1. Cook spaghetti al dente\n2. Fry pancetta until crisp\n3. Whisk eggs with parmesan and pepper\n4. Toss hot pasta with pancetta, then egg mixture off heat",
            AverageRating = 4.8, RatingCount = 12
        },
        new Recipe
        {
            Id = 4, Title = "Chicken Tikka Masala", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = "Chicken thighs\nYogurt\nGaram masala\nTomato sauce\nCream\nRice",
            Steps = "1. Marinate chicken in yogurt and spices\n2. Grill or pan-fry chicken pieces\n3. Simmer tomato sauce with cream and spices\n4. Add chicken to sauce and serve over rice",
            AverageRating = 4.6, RatingCount = 10
        },
        new Recipe
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour",
            Steps = "1. Melt chocolate and butter together\n2. Whisk eggs and sugar until fluffy\n3. Fold in chocolate mixture and flour\n4. Pour into greased ramekins\n5. Bake at 425°F for 12 minutes",
            AverageRating = 4.9, RatingCount = 15
        },
        new Recipe
        {
            Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = "Ladyfingers\nMascarpone\nEspresso\nCocoa powder\nEggs\nSugar",
            Steps = "1. Whisk egg yolks with sugar, fold in mascarpone\n2. Dip ladyfingers in espresso\n3. Layer mascarpone and ladyfingers in dish\n4. Refrigerate overnight\n5. Dust with cocoa before serving",
            AverageRating = 4.7, RatingCount = 9
        }
    };

    private int _nextId = 7;

    public List<Recipe> GetByCategory(string categorySlug)
    {
        return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = totalStars / recipe.RatingCount;
    }
}

