arguments.file_text:
@page "/recipes"
@page "/recipes/{CategorySlug}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Browse Recipes - RecipeShare</PageTitle>

@if (string.IsNullOrEmpty(CategorySlug))
{
    <h1>Browse Recipes</h1>
    <p>Select a category to browse recipes:</p>

    <ul class="list-group">
        <li class="list-group-item"><a href="recipes/appetizers">🥗 Appetizers</a></li>
        <li class="list-group-item"><a href="recipes/main-courses">🍝 Main Courses</a></li>
        <li class="list-group-item"><a href="recipes/desserts">🍰 Desserts</a></li>
    </ul>
}
else
{
    <h1>@CategoryName</h1>
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    @if (Recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="list-group">
            @foreach (var recipe in Recipes)
            {
                <a href="recipe/@recipe.Id" class="list-group-item list-group-item-action">
                    <div class="d-flex w-100 justify-content-between">
                        <h5 class="mb-1">@recipe.Title</h5>
                        <small>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</small>
                    </div>
                </a>
            }
        </div>
    }
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<Recipe> Recipes { get; set; } = new();

    private string CategoryName => CategorySlug switch
    {
        "appetizers" => "🥗 Appetizers",
        "main-courses" => "🍝 Main Courses",
        "desserts" => "🍰 Desserts",
        _ => "Recipes"
    };

    protected override void OnParametersSet()
    {
        if (!string.IsNullOrEmpty(CategorySlug))
        {
            Recipes = RecipeService.GetByCategory(CategorySlug);
        }
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
