            @foreach (var recipe in Recipes)
            {
                <a href="recipe/@recipe.Id" class="list-group-item list-group-item-action">
                    <div class="d-flex w-100 justify-content-between">
                        <h5 class="mb-1">@recipe.Title</h5>
                        <small>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</small>
                    </div>
                </a>
            }
        </div>
    }
}

@code {
    [Parameter]
    public string? CategorySlug { get; set; }

    private List<Recipe> Recipes { get; set; } = new();

    private string CategoryName => CategorySlug switch
    {
        "appetizers" => "🥗 Appetizers",
        "main-courses" => "🍝 Main Courses",
        "desserts" => "🍰 Desserts",
        _ => "Recipes"
    };

    protected override void OnParametersSet()
    {
        if (!string.IsNullOrEmpty(CategorySlug))
        {
            Recipes = RecipeService.GetByCategory(CategorySlug);
        }
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Models
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The requested recipe does not exist.</p>
    <a href="recipes">Back to recipes</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
            <li class="breadcrumb-item"><a href="recipes/@Recipe.CategorySlug">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        </ol>
    </nav>

    <h1>@Recipe.Title</h1>

    <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />

    <h2>Ingredients</h2>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h2>Steps</h2>
    <ol>
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li>@step.TrimStart("0123456789. ".ToCharArray())</li>
        }
    </ol>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@using RecipeShare.Services
@inject RecipeService RecipeService

<div class="my-3">
    <span class="me-2">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <button class="btn btn-link p-0 fs-4 text-decoration-none"
                @onclick="() => SubmitRating(star)"
                title="Rate @star stars"
                disabled="@HasRated">
            @(star <= DisplayRating ? "★" : "☆")
        </button>
    }
    @if (HasRated)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int DisplayRating { get; set; }
    private bool HasRated { get; set; }

    private void SubmitRating(int stars)
    {
        if (HasRated) return;

        RecipeService.AddRating(RecipeId, stars);
        DisplayRating = stars;
        HasRated = true;
    }
}

