@page "/submit"
@using RecipeShare.Models
@using RecipeShare.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "@Model.Title" has been added.
        <a href="recipe/@SubmittedId">View it here</a>.
    </div>
    <button class="btn btn-primary" @onclick="Reset">Submit Another</button>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Model.Title" />
            <ValidationMessage For="() => Model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Model.CategorySlug">
                <option value="">-- Select a category --</option>
                <option value="appetizers">Appetizers</option>
                <option value="main-courses">Main Courses</option>
                <option value="desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => Model.CategorySlug" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Model.Ingredients" />
            <ValidationMessage For="() => Model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="Model.Steps" />
            <ValidationMessage For="() => Model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-primary">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel Model { get; set; } = new();
    private bool Submitted { get; set; }
    private int SubmittedId { get; set; }

    private void HandleSubmit()
    {
        var categoryName = Model.CategorySlug switch
        {
            "appetizers" => "Appetizers",
            "main-courses" => "Main Courses",
            "desserts" => "Desserts",
            _ => "Other"
        };

        var recipe = new Recipe
        {
            Title = Model.Title,
            Category = categoryName,
            CategorySlug = Model.CategorySlug,
            Ingredients = Model.Ingredients,
            Steps = Model.Steps
        };

        RecipeService.AddRecipe(recipe);
        SubmittedId = recipe.Id;
        Submitted = true;
    }

    private void Reset()
    {
        Model = new();
        Submitted = false;
    }
}

using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class RecipeFormModel
{
    [Required(ErrorMessage = "Please enter a recipe title.")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a category.")]
    public string CategorySlug { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please list the ingredients.")]
    public string Ingredients { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please describe the steps.")]
    public string Steps { get; set; } = string.Empty;
}

